#!/usr/bin/env node
/**
 * Embeds public/presentation/index.html into a TS module so /presentation
 * works on Vercel (no runtime fs.readFileSync of untraced public files).
 */
import fs from "node:fs";
import path from "node:path";
import { fileURLToPath } from "node:url";

const root = path.dirname(fileURLToPath(import.meta.url));
const srcHtml = path.join(root, "../public/presentation/index.html");
const outTs = path.join(root, "../src/app/presentation/deck-content.ts");

const html = fs.readFileSync(srcHtml, "utf8");
const banner =
  "// AUTO-GENERATED by scripts/sync-presentation-deck.mjs — edit public/presentation/index.html\n";
const body = `${banner}export const DECK_HTML: string = ${JSON.stringify(html)};\n`;

fs.writeFileSync(outTs, body, "utf8");
console.log(`Wrote ${path.relative(root, outTs)} (${html.length} bytes)`);
